VALUES
  -- Security Skills
  ('sk_secret_scanner', 'secret-scanner', 'Secret Scanner', 'Scans your codebase for hardcoded API keys, passwords, tokens, and credentials. Supports 120+ secret patterns including AWS, GCP, Azure, GitHub, Stripe, and database connection strings. Reports findings with file path, line number, and remediation guidance.', 'security', 'opensyber', '1.2.0', 'approved', datetime('now'), 4821, 4.8, 312, 'free', 0, '{"name":"Secret Scanner","slug":"secret-scanner","version":"1.2.0","description":"Scan codebase for hardcoded secrets","entrypoint":"index.js","permissions":{"network":[],"filesystem":["./"],"env":[]},"author":"OpenSyber"}', 1, 1, datetime('now')),

  ('sk_dep_audit', 'dependency-auditor', 'Dependency Auditor', 'Continuously monitors installed packages for known CVEs using the OSV and NVD databases. Generates SBOM (Software Bill of Materials) in CycloneDX format. Flags critical and high severity vulnerabilities with upgrade paths and patching recommendations.', 'security', 'opensyber', '2.0.1', 'approved', datetime('now'), 3654, 4.7, 248, 'free', 0, '{"name":"Dependency Auditor","slug":"dependency-auditor","version":"2.0.1","description":"Monitor dependencies for CVEs","entrypoint":"index.js","permissions":{"network":["osv.dev","services.nvd.nist.gov"],"filesystem":["./"],"env":[]},"author":"OpenSyber"}', 1, 1, datetime('now')),

