  ('sk_iac_scanner', 'iac-scanner', 'IaC Security Scanner', 'Static analysis for Infrastructure as Code templates. Scans Terraform, CloudFormation, Pulumi, and Kubernetes manifests for security misconfigurations, overly permissive IAM policies, unencrypted storage, and public-facing resources before deployment.', 'security', 'opensyber', '1.0.0', 'approved', datetime('now'), 1456, 4.4, 98, 'free', 0, '{"name":"IaC Security Scanner","slug":"iac-scanner","version":"1.0.0","description":"Scan IaC templates for misconfigs","entrypoint":"index.js","permissions":{"network":[],"filesystem":["./"],"env":[]},"author":"OpenSyber"}', 0, 1, datetime('now')),

  ('sk_supply_chain', 'supply-chain-guard', 'Supply Chain Guard', 'Monitors npm, PyPI, and Go module installations for supply chain attack indicators. Detects typosquatting, suspicious postinstall scripts, unexpected network calls, and known malicious packages using the Socket.dev threat feed and OpenSyber threat intelligence.', 'security', 'opensyber', '1.3.0', 'approved', datetime('now'), 2934, 4.9, 201, 'free', 0, '{"name":"Supply Chain Guard","slug":"supply-chain-guard","version":"1.3.0","description":"Detect supply chain attacks in dependencies","entrypoint":"index.js","permissions":{"network":["api.socket.dev"],"filesystem":["./"],"env":["SOCKET_API_KEY"]},"author":"OpenSyber"}', 1, 1, datetime('now')),

